<template>
  <v-container fluid fill-height align-start ma-0 pa-2 class="noticE">
    <i-dx-popup
      :popupVisible="popupVisible"
      :title="`${$t('announcement')} ${$t('fileManagement')}`"
      :key="popupData.seq"
      @popupCloseButtonClick="popupCloseButtonClick()"
      height="665px"
      width="90vw"
      max-width="958px"
    >
      <template v-slot:grid>
        <i-file-upload
          :headerTitle="`${$t('announcement')} ${$t('fileManagement')}`"
          :targetId="`${popupData.seq}`"
          targetType="notice"
          @fileListChange="fileListChange(`${popupData.seq}`, $event)"
        >
          <template v-slot:titleLayout>
            <i-card-top class="align-end" style="margin-bottom: 0px !important;">
              <template v-slot:body>
                <div class="v-application">
                  <v-row no-gutters class="pa-4" style="background:#EEF2F5;">
                    <v-col cols="12" md="6" class="d-flex font-weight-bold text-caption">
                      <div class="content--text mr-1 text-caption">
                        <v-icon x-small>mdi-square-small</v-icon>
                        {{ $t('title') }} :
                      </div>
                      <div class="primary--text">{{ '\u00A0' + (popupData.subject || '') }}</div>
                    </v-col>
                    <v-col cols="12" md="6" class="d-flex font-weight-bold text-caption">
                      <div class="content--text mr-1 text-caption">
                        <v-icon x-small>mdi-square-small</v-icon>
                        {{ $t('writer') }} :
                      </div>
                      <div class="primary--text">{{ '\u00A0' + (popupData.userNm || '') }}</div>
                    </v-col>
                  </v-row>
                </div>
              </template>
            </i-card-top>
          </template>
        </i-file-upload>
      </template>
    </i-dx-popup>
    <v-row no-gutters>
      <v-col cols="12" sm="12" lg="12" class="pa-2 pb-0">
        <i-card-top
          class="d-md-flex"
          headerTitle=""
          :useBtnList="buttonUseList"
          @btnSearch="btnSearch()"
          @btnAdd="btnAdd()"
          @btnSave="btnSave()"
          @btnDelete="btnDelete()"
        >
          <template v-slot:body>
            <v-layout>
              <v-row no-gutters class="center pa-0 pa-md-2 pb-0"> </v-row>
            </v-layout>
          </template>
        </i-card-top>
      </v-col>
      <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
        <i-card-vertical :headerTitle="$t('announcement')" device="multi">
          <template v-slot:body>
            <v-layout column>
              <v-col cols="12" md="12" class="row pa-0">
                <v-col cols="12" lg="12" class="pa-0 ">
                  <DxDataGrid
                    id="NoticeGrid"
                    class="layout-col-height00"
                    width="100%"
                    :ref="dxDataGridRef"
                    :data-source="gridMain"
                    :remote-operations="false"
                    :hover-state-enabled="true"
                    :allow-column-resizing="true"
                    :allow-column-reordering="true"
                    :row-alternation-enabled="true"
                    :column-auto-width="false"
                    :column-auto-height="true"
                    :show-borders="true"
                    :show-row-lines="true"
                    :column-hiding-enabled="false"
                    :focused-row-enabled="true"
                    :selection="{ mode: 'single' }"
                    key-expr="seq"
                    @editing-start="onEditingStart"
                    @editor-preparing="
                      e => {
                        onEditorPreparing(e)
                        dispDateSetting(e)
                      }
                    "
                  >
                    <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />

                    <DxSelection select-all-mode="allMode" show-check-boxes-mode="always" mode="multiple" />

                    <DxColumn data-field="compId" data-type="string" :visible="false"> </DxColumn>
                    <!-- <DxColumn data-field="seq" data-type="number" :visible="false"> </DxColumn> -->
                    <DxColumn
                      data-field="subject"
                      :caption="$t('title')"
                      data-type="string"
                      alignment="left"
                      :editorOptions="{ maxLength: 180 }"
                      :allow-sorting="false"
                      css-class="devest-grid-header-require"
                    >
                    </DxColumn>

                    <DxColumn
                      data-field="userNm"
                      :caption="$t('writer')"
                      width="120px"
                      data-type="string"
                      alignment="center"
                      :allow-editing="false"
                    />
                    <DxColumn
                      data-field="utUserNm"
                      :caption="$t('modifier')"
                      width="120px"
                      data-type="string"
                      alignment="center"
                      :allow-editing="false"
                      cell-template="utUserNm"
                    />
                    <template #utUserNm="{ data: cellInfo }">
                      {{ cellInfo.text || '-' }}
                    </template>
                    <DxColumn
                      data-field="createdAt"
                      data-type="date"
                      format="yyyy.MM.dd"
                      width="100px"
                      alignment="center"
                      :caption="$t('createdDate')"
                      edit-cell-template="dateEditor"
                      :allow-editing="false"
                    />
                    <DxColumn
                      data-field="dispStDate"
                      data-type="date"
                      format="yyyy.MM.dd"
                      width="100px"
                      alignment="center"
                      :caption="$t('postingStart')"
                      edit-cell-template="dateEditor"
                      css-class="devest-grid-header-require"
                    />
                    <DxColumn
                      data-field="dispEdDate"
                      data-type="date"
                      format="yyyy.MM.dd"
                      width="100px"
                      alignment="center"
                      :caption="$t('postingEnd')"
                      edit-cell-template="dateEditor"
                      css-class="devest-grid-header-require"
                    />
                    <DxColumn
                      name="file"
                      :caption="$t('fileManagement')"
                      width="200px"
                      data-type="string"
                      alignment="left"
                      cell-template="file-manage-template"
                      :calculate-display-value="
                        element => {
                          return element.fileNm
                        }
                      "
                      :allow-editing="false"
                    />
                    <template #dateEditor="{ data: cellInfo}">
                      <div>
                        <DxDateBox
                          :value="cellInfo.value"
                          type="date"
                          picker-type="calendar"
                          display-format="yyyy.MM.dd"
                          :use-mask-behavior="true"
                          :max="handleDateMinMax(cellInfo, 'max')"
                          :min="handleDateMinMax(cellInfo, 'min')"
                          @opened="handleDateBox($event, cellInfo, true)"
                          @closed="handleDateBox($event, cellInfo, false)"
                          @value-changed="onDateValueChanged($event, cellInfo)"
                        />
                      </div>
                    </template>
                    <template #file-manage-template="{ data : cellInfo }">
                      <v-row v-if="!cellInfo.data.__created__" no-gutters class="px-2 align-center" style="flex-flow: nowrap;">
                        <div style="text-overflow: ellipsis; overflow: hidden;">
                          {{ cellInfo.displayValue }}
                        </div>
                        <div>
                          {{ cellInfo.data.fileCount }}
                        </div>
                        <v-spacer />
                        <v-btn
                          small
                          class="pa-0"
                          icon
                          @click="
                            () => {
                              popupData = cellInfo.data || {}
                              popupVisible = true
                            }
                          "
                        >
                          <svg-icon icon-class="searching"></svg-icon>
                        </v-btn>
                      </v-row>
                    </template>

                    <DxColumn
                      data-field="content"
                      :caption="$t('content')"
                      data-type="string"
                      alignment="left"
                      cell-template="sub-dx-datagrid"
                      edit-cell-template="sub-dx-datagrid"
                    >
                    </DxColumn>
                    <template #sub-dx-datagrid="{ data : cellInfo }">
                      <div class="yunju_calss">
                        <DxTextArea
                          :auto-resize-enabled="true"
                          :min-height="0"
                          v-model="cellInfo.value"
                          :on-value-changed="
                            e => {
                              cellInfo.setValue(e.value, e.value)
                              cellInfo.component.selectRows(cellInfo.row.key, true)
                            }
                          "
                          :on-key-down="
                            e => {
                              if (e.event.keyCode == 13) {
                                e.event.stopPropagation()
                              }
                            }
                          "
                        />
                      </div>
                    </template>
                  </DxDataGrid>
                </v-col>
              </v-col>
            </v-layout>
          </template>
        </i-card-vertical>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { DxDataGrid, DxColumn, DxSelection, DxLookup, DxEditing, DxFilterRow } from 'devextreme-vue/data-grid'
import DxCheckBox from 'devextreme-vue/check-box'
import iCardTop from '@/components/common/iCardTop.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'
import { getNotice, saveNotice, deleteNotice } from '@/api/board/notice/notice'
import { getUserCd } from '@/utils/token'
import { getCurrentDate, getDateEditorValue } from '@/utils/common.js'
import IDxPopup from '@/components/common/iDxPopup.vue'
import IFileUpload from '@/components/common/iFileUpload.vue'
import DxDateBox from 'devextreme-vue/date-box'
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue' //20220509 LYJ 데이타 그리드 사용시 베이스 추가

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가 및 권한 처리
  components: {
    DxDataGrid,
    DxColumn,
    DxSelection,
    DxEditing,
    'i-card-vertical': iCardVertical,
    'i-card-top': iCardTop,
    IDxPopup,
    DxDateBox,
    IFileUpload
  },
  data() {
    return {
      dxDataGridRef: 'NoticeGrid',
      gridMain: [],
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd', //추가
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      dxFileUploaderRef: 'uploaderContainer',
      fileData: {},
      currentCellInfo: null,
      // file popup
      popupData: {},
      popupVisible: false
    }
  },
  beforeMount() {
    this.BaseInitialize()
    this.datagridRefs = [this.dxDataGridRef]
  },
  mounted() {},

  computed: {},
  activated() {
    if (this.$route.params) {
      this.btnSearch().then(res => {
        if (this.$route.params.focusedRowKey) this.DataGrids[0].option('focusedRowKey', this.$route.params.focusedRowKey)
      })
    }
  },
  methods: {
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////
    btnAdd() {
      let currentDate = getCurrentDate()
        .split('-')
        .join('.')
      const createdArr = this.gridMain.filter(el => el.__created__)
      const newId = (Math.max(...createdArr.map(obj => obj.seq)) || 0) + 1
      let newRow = {
        seq: createdArr.length !== 0 ? newId : Math.max(...this.gridMain.map(obj => obj.seq)||0)+1,
        dispStDate: currentDate,
        dispEdDate: currentDate
      }
      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
      this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.seq, true)
    },
    btnSearch() {
      return new Promise((resolve, reject) => {
        this.openLoading()
        getNotice(true)
          .then(res => {
            if (res.success) {
              this.gridMain = res.list.map(el => el)
              this.gridInit(this.DataGrids[0])
              this.FocusFirstRow(this.DataGrids[0])
              resolve(true)
            }
          })
          .catch(e => {
            console.error(e)
            reject()
          })
          .finally(() => this.endLoading())
      })
    },
    async btnSave() {
      this.DataGrids[0].saveEditData()
      const currentSelectedRows = await this.DataGrids[0].getSelectedRowsData()
      // trim
      const trimList = ['subject', 'content']
      let selectedRows = currentSelectedRows.map(el => {
        trimList.forEach(key => el[key] && (el[key] = el[key].trim()))
        return el
      })
      if (selectedRows.length === 0) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      if (selectedRows.every(el => !el.subject || !el.dispStDate)) {
        this.vToastify(`${this.$t('msgReqValidate')}[${this.$t('title')},${this.$t('postingStart')}]`, 'warn')
        this.GetDataGrid(this.dxDataGridRef).endUpdate()
        return
      }

      this.vToastifyPrompt(this.$t('doSaveData'), 'info', current => {
        this.openLoading()
        selectedRows.forEach(element => {
          element.compId = this.getCompId()
          element.userCd = getUserCd()
        })

        saveNotice(selectedRows, true)
          .then(() => {
            this.btnSearch()
          })
          .finally(() => {
            this.endLoading()
          })
      })
    },

    async btnDelete() {
      let selectedRows = await this.GetDataGrid(this.dxDataGridRef).getSelectedRowsData()
      if (selectedRows.length === 0) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }

      this.vToastifyPrompt(
        this.$t('doDeleteData'),
        'info',
        current => {
          this.GetDataGrid(this.dxDataGridRef).beginUpdate()
          this.GetDataGrid(this.dxDataGridRef).saveEditData()
          this.openLoading('deleting')
          const param = selectedRows.filter(el => !el.__created__)
          const newIds = selectedRows.filter(el => el.__created__).map(el => el.seq)
          this.gridMain = this.gridMain.filter(el => !newIds.includes(el.seq))
          const finishEvent = () => {
            this.GetDataGrid(this.dxDataGridRef).endUpdate()
            this.endLoading()
          }
          if (param.length !== 0) {
            deleteNotice(param, true)
              .then(() => {
                this.deleteCallBack(param)
              })
              .catch(e => console.error(e))
              .finally(() => finishEvent())
          } else {
            finishEvent()
          }
        },
        null,
        true
      )
    },

    popupCloseButtonClick() {
      this.popupVisible = false
    },

    ///////////////////////////////////////
    /*        DataGrid Event Event       */
    ///////////////////////////////////////
    //행 cell에서 데이터 수정후 저장을 누르면 선택된 데이터가 없다는 메세지가 발생
    //위 문제를 해결하기 위해서 아래 소스코드 구현

    ///////////////////////////////////////
    /*             etc Event             */
    ///////////////////////////////////////
    deleteCallBack(selectedRows) {
      var index = null
      selectedRows.forEach(key => {
        index = this.gridMain.findIndex(obj => obj == key)
        this.gridMain.splice(index, 1)
      })
    },
    //추가된 행이 아니면 수정 불가능하게 설정
    onEditingStart(e) {
      // if (e.column.dataField == 'workPlaceId' && !e.data.__created__) e.cancel = true
      // else e.cancel = false
    },
    dispDateSetting(e) {
      if (e.parentType == 'dataRow') {
        if (e.dataField == 'dispStDate') {
          e.editorOptions.max = e.row.data.dispEdDate
        } else if (e.dataField == 'dispEdDate') {
          e.editorOptions.min = e.row.data.dispStDate
        }
      }
    },
    onDateValueChanged(event, cellInfo) {
      const { dataField } = cellInfo.column
      const range = dataField === 'dispStDate' ? 'dispEdDate' : 'dispStDate'

      //날짜 세팅
      let currentDate = getDateEditorValue(event.value)
      let targetDate = getDateEditorValue(cellInfo.data[range])
      const setDate =
        currentDate &&
        targetDate &&
        ((dataField === 'dispStDate' && currentDate > targetDate) || (dataField === 'dispEdDate' && currentDate < targetDate))
          ? cellInfo.data[range]
          : event.value || null

      //그리드 삽입
      const cell = this.gridMain[cellInfo.rowIndex]
      cell[cellInfo.column.dataField] = currentDate
      cellInfo.setValue(currentDate)
      this.$refs[this.dxDataGridRef].instance.selectRows(cellInfo.row.key, true)
    },
    handleDateMinMax(cellInfo, type) {
      const row = this.gridMain[cellInfo.rowIndex]
      if (!row) return undefined
      const dateField = type === 'max' ? 'dispEdDate' : 'dispStDate'
      return row[dateField] ? new Date(row[dateField]) : undefined
    },
    handleDateBox(event, cellInfo, isOpened) {
      const { dataField } = cellInfo.column
      const range = dataField == 'dispStDate' ? 'min' : 'max'
      event.component.option(range, isOpened ? null : new Date(cellInfo.text))
    },
    fileListChange(id, el) {
      let obj = this.gridMain.find(item => item.seq == id)
      obj.fileNm = el.fileNm
      obj.fileCount = el.fileCnt
      this.GetDataGrid(this.dxDataGridRef).saveEditData()
    }
  }
}
</script>

<style lang="scss">
.dx-command-select {
  width: 30px !important;
  min-width: 30px !important;
}

